import React, { useState, useEffect } from 'react';
import './App.css';
import Login from './components/Login';
import AdminDashboard from './components/AdminDashboard';
import Products from './components/Products';
import Sales from './components/Sales';
import PartnerDashboard from './components/PartnerDashboard';
import PartnerProducts from './components/PartnerProducts';
import PartnerSales from './components/PartnerSales';
import PartnerBuyers from './components/PartnerBuyers';
import { authService } from './services/api';
import { LayoutDashboard, Package, ShoppingCart, Users, LogOut } from 'lucide-react';

function App() {
  const [user, setUser] = useState(null);
  const [currentPage, setCurrentPage] = useState('dashboard');

  useEffect(() => {
    const savedUser = authService.getCurrentUser();
    if (savedUser) {
      console.log('Loaded user from storage:', savedUser);
      setUser(savedUser);
    }
  }, []);

  const handleLogin = (userData) => {
    console.log('User logged in:', userData);
    setUser(userData);
    setCurrentPage('dashboard');
  };

  const handleLogout = () => {
    console.log('User logged out');
    authService.logout();
    setUser(null);
    setCurrentPage('dashboard');
  };

  const renderContent = () => {
    if (!user) {
      return <Login onLogin={handleLogin} />;
    }

    // Admin pages
    if (user.userRole === 'Admin') {
      switch (currentPage) {
        case 'dashboard':
          return <AdminDashboard />;
        case 'products':
          return <Products />;
        case 'sales':
          return <Sales />;
        default:
          return <AdminDashboard />;
      }
    }

    // Partner pages
    if (user.userRole === 'Partner') {
      switch (currentPage) {
        case 'dashboard':
          return <PartnerDashboard />;
        case 'products':
          return <PartnerProducts />;
        case 'buyers':
          return <PartnerBuyers />;
        case 'sales':
          return <PartnerSales />;
        default:
          return <PartnerDashboard />;
      }
    }

    // Buyer or other roles
    return (
      <div style={{ 
        padding: '2rem', 
        maxWidth: '800px', 
        margin: '0 auto',
        background: 'white',
        borderRadius: '10px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)'
      }}>
        <h1>Welcome, {user?.fullName || 'User'}!</h1>
        <div style={{ marginTop: '1rem', color: '#666' }}>
          <p><strong>Role:</strong> {user?.userRole || 'N/A'}</p>
          <p><strong>Email:</strong> {user?.email || 'N/A'}</p>
          {user?.companyName && <p><strong>Company:</strong> {user.companyName}</p>}
        </div>
        <p style={{ marginTop: '2rem', color: '#999' }}>
          Your dashboard is being prepared. Please contact support if you need access to specific features.
        </p>
      </div>
    );
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="app">
      {/* Sidebar */}
      <aside className="sidebar">
        <div className="sidebar-header">
          <h2 className="sidebar-title">Sales ERP</h2>
          <p className="sidebar-subtitle">{user?.userRole || 'User'} Panel</p>
        </div>

        <nav className="sidebar-nav">
          {user.userRole === 'Admin' && (
            <>
              <button
                className={`nav-item ${currentPage === 'dashboard' ? 'active' : ''}`}
                onClick={() => setCurrentPage('dashboard')}
              >
                <LayoutDashboard size={20} />
                <span>Dashboard</span>
              </button>
              <button
                className={`nav-item ${currentPage === 'products' ? 'active' : ''}`}
                onClick={() => setCurrentPage('products')}
              >
                <Package size={20} />
                <span>Products</span>
              </button>
              <button
                className={`nav-item ${currentPage === 'sales' ? 'active' : ''}`}
                onClick={() => setCurrentPage('sales')}
              >
                <ShoppingCart size={20} />
                <span>Sales</span>
              </button>
            </>
          )}

          {user.userRole === 'Partner' && (
            <>
              <button
                className={`nav-item ${currentPage === 'dashboard' ? 'active' : ''}`}
                onClick={() => setCurrentPage('dashboard')}
              >
                <LayoutDashboard size={20} />
                <span>Dashboard</span>
              </button>
              <button
                className={`nav-item ${currentPage === 'products' ? 'active' : ''}`}
                onClick={() => setCurrentPage('products')}
              >
                <Package size={20} />
                <span>Products</span>
              </button>
              <button
                className={`nav-item ${currentPage === 'buyers' ? 'active' : ''}`}
                onClick={() => setCurrentPage('buyers')}
              >
                <Users size={20} />
                <span>My Buyers</span>
              </button>
              <button
                className={`nav-item ${currentPage === 'sales' ? 'active' : ''}`}
                onClick={() => setCurrentPage('sales')}
              >
                <ShoppingCart size={20} />
                <span>Sales</span>
              </button>
            </>
          )}

          {user.userRole === 'Buyer' && (
            <button
              className={`nav-item ${currentPage === 'dashboard' ? 'active' : ''}`}
              onClick={() => setCurrentPage('dashboard')}
            >
              <LayoutDashboard size={20} />
              <span>Dashboard</span>
            </button>
          )}
        </nav>

        <div className="sidebar-footer">
          <div className="user-info">
            <div className="user-avatar">
              {(user?.fullName || 'U').charAt(0).toUpperCase()}
            </div>
            <div className="user-details">
              <div className="user-name">{user?.fullName || 'User'}</div>
              <div className="user-email">{user?.email || 'user@example.com'}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>
            <LogOut size={20} />
            <span>Logout</span>
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        {renderContent()}
      </main>
    </div>
  );
}

export default App;
